            missing.append("variance")

        # Must contain @d.reyes or 'escalated' or similar escalation language
        if not any(kw in text for kw in ["d.reyes", "reyes", "escalat"]):
            missing.append("'@d.reyes' or 'escalated'")

        if not missing:
            return {"pass": True, "score": 1.0, "feedback": f"Found dc-escalations post for manifest 2026-04-15-003 with P2, variance, and escalation to d.reyes. Message: {msg.get('text', '')[:200]}"}

