        if len(missing) <= 2:
            best_match_details.append({"text": msg.get("text", "")[:200], "missing": missing})

    if best_match_details:
        closest = min(best_match_details, key=lambda x: len(x["missing"]))
        return {"pass": False, "score": 0.0, "feedback": f"Found near-match in #dc-escalations but missing: {', '.join(closest['missing'])}. Closest message: {closest['text']}"}

