from pathlib import Path
import openpyxl
import re
import datetime


def _cell_str(val):
    """Normalize a cell value to a comparable string."""
    if val is None:
        return ""
    return str(val).strip()


def _num_close(cell_val, expected, tol=1.0):
    """Check whether a cell value is numerically close to expected (absolute tolerance)."""
    try:
        s = str(cell_val).strip()
        # Remove degree symbols, C/F suffixes
        s = re.sub(r'[°CF]+', '', s).strip()
        cv = float(s)
        ev = float(expected)
        return abs(cv - ev) <= tol
    except (ValueError, TypeError):
        return False


def _text_contains(cell_val, substring):
    cv = _cell_str(cell_val).lower()
    return substring.lower() in cv


def _date_match(cell_val, expected_str):
    """Accept '2026-04-15' as string, or a datetime date."""
    cv = cell_val
    if cv is None:
        return False
    if isinstance(cv, datetime.datetime):
        return cv.strftime("%Y-%m-%d") == expected_str
    if isinstance(cv, datetime.date):
        return cv.strftime("%Y-%m-%d") == expected_str
    s = str(cv).strip()
    if s == expected_str:
        return True
    # Try parsing
    for fmt in ("%Y-%m-%d", "%m/%d/%Y", "%Y/%m/%d", "%d-%m-%Y"):
        try:
            d = datetime.datetime.strptime(s, fmt)
            if d.strftime("%Y-%m-%d") == expected_str:
                return True
        except ValueError:
            pass
    return False


def _time_match_any(cell_val, expected_options):
    """Check if cell_val matches any of the expected time strings."""
    cv = cell_val
    if cv is None:
        return False
    for expected_str in expected_options:
        if _time_match_single(cv, expected_str):
            return True
    return False


