    if cv is None:
        return False
    if isinstance(cv, datetime.time):
        parts = expected_str.split(":")
        return cv.hour == int(parts[0]) and cv.minute == int(parts[1])
    if isinstance(cv, datetime.datetime):
        parts = expected_str.split(":")
        return cv.hour == int(parts[0]) and cv.minute == int(parts[1])
    s = str(cv).strip()
    def norm_time(t):
        p = t.split(":")
        if len(p) >= 2:
            return f"{int(p[0])}:{p[1].zfill(2)}"
        return t
    return norm_time(s) == norm_time(expected_str) or s == expected_str


def _find_file(workspace_path):
    """Find temperature_log.xlsx, being flexible about location."""
    fp = Path(workspace_path) / "temperature_log.xlsx"
    if fp.exists():
        return fp
    results = list(Path(workspace_path).glob("**/temperature_log.xlsx"))
    if results:
        return results[0]
    results = list(Path(workspace_path).glob("**/*temperature*.xlsx"))
    if results:
        return results[0]
    return None


def verify(workspace_path, external_services_path=None):
