from pathlib import Path
import openpyxl
import re
from datetime import datetime, date


def verify(workspace_path, external_services_path=None):
    # Try to find inbound_receiving_log.xlsx - search broadly
    filepath = Path(workspace_path) / 'inbound_receiving_log.xlsx'
    if not filepath.exists():
        # Try glob
        candidates = list(Path(workspace_path).glob('**/inbound_receiving_log.xlsx'))
        if candidates:
            filepath = candidates[0]
        else:
            return {"pass": False, "score": 0.0, "feedback": f"File not found: inbound_receiving_log.xlsx in {workspace_path}"}

    try:
        wb = openpyxl.load_workbook(str(filepath))
        ws = wb.active
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error opening workbook: {e}"}

    # Try to find the correct row - check rows 2 through 30 for our shipment ID
    target_row = None
    for r in range(2, 31):
        val_b = ws[f"B{r}"].value
        if val_b is not None:
            val_str = str(val_b).strip()
            if '2026-04-15-001' in val_str:
                target_row = r
                break

    # If not found by shipment ID, try finding by date in column A
    if target_row is None:
        for r in range(2, 31):
            val_a = ws[f"A{r}"].value
            if val_a is not None:
                if isinstance(val_a, (datetime, date)):
                    if val_a.strftime("%Y-%m-%d") == "2026-04-15":
                        target_row = r
                        break
                elif '2026-04-15' in str(val_a):
                    target_row = r
                    break

    # Default to row 12 as specified in rubric
    if target_row is None:
        target_row = 12

    row = target_row
    issues = []
    passes = []
    total_checks = 15  # A, B, C, D, E, F, G, H, I, J, K, L, M, N, and P-or-Q status

    def cell_val(col_letter):
        cell = ws[f"{col_letter}{row}"]
        return cell.value

    def normalize(val):
        if val is None:
            return ""
        if isinstance(val, (datetime, date)):
            return val.strftime("%Y-%m-%d")
        return str(val).strip()

    def check_numeric(val, expected, label, tolerance=0.1):
        nval = normalize(val)
        # Try to extract a number from the string
        try:
            num_val = float(nval)
        except (ValueError, TypeError):
            # Try regex to find a number
            match = re.search(r'-?[\d.]+', nval)
            if match:
                try:
                    num_val = float(match.group())
                except (ValueError, TypeError):
                    return False, f"{label}: expected ~{expected}, got '{nval}' (not numeric)"
            else:
                return False, f"{label}: expected ~{expected}, got '{nval}' (not numeric)"
        try:
            num_exp = float(expected)
        except (ValueError, TypeError):
            return False, f"{label}: could not parse expected value '{expected}'"
        if num_exp == 0:
            if abs(num_val) < 1:
                return True, f"{label}: found {num_val} (expected {num_exp})"
            else:
                return False, f"{label}: expected {num_exp}, got {num_val}"
        if abs(num_val - num_exp) / max(abs(num_exp), 1e-9) <= tolerance:
            return True, f"{label}: found {num_val} (expected {num_exp})"
        return False, f"{label}: expected {num_exp}, got {num_val}"

    def check_string(val, expected, label, exact=False):
        nval = normalize(val).lower()
        nexp = expected.lower().strip()
        if exact:
            if nval == nexp:
                return True, f"{label}: found '{normalize(val)}'"
            return False, f"{label}: expected '{expected}', got '{normalize(val)}'"
        if nexp in nval or nval == nexp:
            return True, f"{label}: found '{normalize(val)}'"
        return False, f"{label}: expected '{expected}', got '{normalize(val)}'"

    def check_date(val, expected_str, label):
        nval = normalize(val)
        if expected_str in nval:
            return True, f"{label}: found '{nval}'"
        if isinstance(val, (datetime, date)):
            formatted = val.strftime("%Y-%m-%d")
            if formatted == expected_str:
                return True, f"{label}: found date '{formatted}'"
        # Also try other date formats
        if nval:
            # Try mm/dd/yyyy, m/d/yyyy, etc.
            for fmt in ["%m/%d/%Y", "%m-%d-%Y", "%Y/%m/%d", "%d-%m-%Y", "%d/%m/%Y"]:
                try:
                    parsed = datetime.strptime(nval, fmt)
                    if parsed.strftime("%Y-%m-%d") == expected_str:
                        return True, f"{label}: found '{nval}' (parsed as {expected_str})"
                except ValueError:
                    pass
        return False, f"{label}: expected '{expected_str}', got '{nval}'"

    # Column A: Date 2026-04-15
    ok, msg = check_date(cell_val('A'), '2026-04-15', 'Col A (Date)')
    (passes if ok else issues).append(msg)

    # Column B: 2026-04-15-001
    ok, msg = check_string(cell_val('B'), '2026-04-15-001', 'Col B (Shipment ID)')
    (passes if ok else issues).append(msg)

    # Column C: Waco Transfer
    val_c = normalize(cell_val('C')).lower()
    ok, msg = check_string(cell_val('C'), 'Waco Transfer', 'Col C (Source)')
    if not ok:
        # Also accept just 'waco' loosely
        if 'waco' in val_c:
            ok = True
            msg = f"Col C (Source): found '{normalize(cell_val('C'))}' (accepted as Waco Transfer)"
    (passes if ok else issues).append(msg)

    # Column D: 26
    ok, msg = check_numeric(cell_val('D'), '26', 'Col D')
    (passes if ok else issues).append(msg)

    # Column E: 26
    ok, msg = check_numeric(cell_val('E'), '26', 'Col E')
    (passes if ok else issues).append(msg)

    # Column F: 492
    ok, msg = check_numeric(cell_val('F'), '492', 'Col F')
    (passes if ok else issues).append(msg)

    # Column G: 492
    ok, msg = check_numeric(cell_val('G'), '492', 'Col G')
    (passes if ok else issues).append(msg)

    # Column H: -18
    ok, msg = check_numeric(cell_val('H'), '-18', 'Col H')
    (passes if ok else issues).append(msg)

    # Column I: -16
    ok, msg = check_numeric(cell_val('I'), '-16', 'Col I')
    (passes if ok else issues).append(msg)

    # Column J: -20
    ok, msg = check_numeric(cell_val('J'), '-20', 'Col J')
    (passes if ok else issues).append(msg)

    # Column K: -18
    ok, msg = check_numeric(cell_val('K'), '-18', 'Col K')
    (passes if ok else issues).append(msg)

    # Column L: Tier 1
    ok, msg = check_string(cell_val('L'), 'Tier 1', 'Col L (Tier)')
    if not ok:
        nval = normalize(cell_val('L')).lower().replace(' ', '')
        if 'tier1' in nval or '1' in nval:
            ok = True
            msg = f"Col L (Tier): found '{normalize(cell_val('L'))}' (accepted as Tier 1)"
    (passes if ok else issues).append(msg)

    # Column M: ~0
    val_m = cell_val('M')
    nval_m = normalize(val_m)
    ok_m = False
    # Accept 0, 0.0, 0%, empty-ish, "none", "n/a"
    if val_m is None or nval_m == '' or nval_m.lower() in ['none', 'n/a', 'na', '-']:
        ok_m = True
        msg_m = f"Col M: found '{nval_m}' (accepted as ~0)"
    else:
        # Try to parse as percent
        pct_match = re.search(r'(-?[\d.]+)\s*%', nval_m)
        if pct_match:
            pct_val = float(pct_match.group(1))
            if abs(pct_val) < 2:
                ok_m = True
                msg_m = f"Col M: found '{nval_m}' (accepted as ~0%)"
        if not ok_m:
            ok_m, msg_m = check_numeric(val_m, '0', 'Col M')
    (passes if ok_m else issues).append(msg_m)

    # Column N: ~0 or 0%
    val_n = cell_val('N')
    nval_n = normalize(val_n)
    ok_n = False
    if val_n is None or nval_n == '' or nval_n.lower() in ['none', 'n/a', 'na', '-']:
        ok_n = True
        msg_n = f"Col N: found '{nval_n}' (accepted as ~0)"
    else:
        # Try to parse as percent
        pct_match = re.search(r'(-?[\d.]+)\s*%', nval_n)
        if pct_match:
            pct_val = float(pct_match.group(1))
            if abs(pct_val) < 2:
                ok_n = True
                msg_n = f"Col N: found '{nval_n}' (accepted as ~0%)"
        if not ok_n:
            ok_n, msg_n = check_numeric(val_n, '0', 'Col N')
    (passes if ok_n else issues).append(msg_n)

    # Column P or Column Q: "Pending Put-Away" (or similar status text)
    # Check columns O through R to be generous
    status_ok = False
    status_msg = ""

    for col in ['O', 'P', 'Q', 'R']:
        val = normalize(cell_val(col)).lower()
        if not val:
            continue
        if 'pending put-away' in val or 'pending put away' in val or 'pending putaway' in val:
            status_ok = True
            status_msg = f"Status: found '{normalize(cell_val(col))}' in Col {col}"
            break
        if 'pending' in val and ('put' in val or 'away' in val):
            status_ok = True
            status_msg = f"Status: found '{normalize(cell_val(col))}' in Col {col} (loosely accepted)"
            break
        if 'received' in val and 'pending' in val:
            status_ok = True
            status_msg = f"Status: found '{normalize(cell_val(col))}' in Col {col} (loosely accepted)"
            break

    if not status_ok:
        val_p = normalize(cell_val('P'))
        val_q = normalize(cell_val('Q'))
        status_msg = f"Status: expected 'Pending Put-Away' in Col P or Q, got P='{val_p}', Q='{val_q}'"

    (passes if status_ok else issues).append(status_msg)

    num_passed = len(passes)
    score = num_passed / total_checks
    passed = len(issues) == 0

    feedback_parts = []
    feedback_parts.append(f"Checking row {row} (rubric specifies row 12)")
    if passes:
        feedback_parts.append("PASSED CHECKS:\n" + "\n".join(f"  \u2713 {p}" for p in passes))
    if issues:
        feedback_parts.append("FAILED CHECKS:\n" + "\n".join(f"  \u2717 {i}" for i in issues))
    feedback_parts.append(f"\nScore: {num_passed}/{total_checks}")

    return {"pass": passed, "score": score, "feedback": "\n".join(feedback_parts)}

from pathlib import Path
import openpyxl
import re
from datetime import datetime, date

def verify(workspace_path, external_services_path=None):
    # Try to find the file using glob first, then exact path
    workspace = Path(workspace_path)
    candidates = list(workspace.glob('**/inbound_receiving_log.xlsx'))
    if candidates:
        file_path = candidates[0]
    else:
        file_path = workspace / 'inbound_receiving_log.xlsx'

    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found: inbound_receiving_log.xlsx in {workspace_path}"}

    try:
        wb = openpyxl.load_workbook(str(file_path))
        ws = wb.active
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to open workbook: {e}"}

    # We'll search rows 10-25 for a row that contains '2026-04-15-003' in column B
    target_row = None
    for r in range(10, 25):
        cell_val = ws.cell(row=r, column=2).value
        if cell_val is not None and '003' in str(cell_val):
            target_row = r
            break
    if target_row is None:
        target_row = 14  # fallback to expected row

    row = target_row
    errors = []
    matches = []

    def normalize(val):
        if val is None:
            return ""
        if isinstance(val, datetime):
            return val.strftime("%Y-%m-%d")
        if isinstance(val, date):
            return val.strftime("%Y-%m-%d")
        return str(val).strip()

    def numbers_close(actual_str, expected_str, tol=0.15):
        """Check if two values are numerically close within tolerance."""
        try:
            a_str = actual_str.replace('%', '').replace(',', '').replace('\u2212', '-').replace('\u2013', '-').strip()
            e_str = expected_str.replace('%', '').replace(',', '').strip()
            a = float(a_str)
            e = float(e_str)
            if e == 0:
                return abs(a) < 1.0
            return abs(a - e) / max(abs(e), 1e-9) <= tol
        except (ValueError, AttributeError):
            return False

    def check_cell(col_letter, expected, col_idx):
        cell_val = ws.cell(row=row, column=col_idx).value
        actual = normalize(cell_val)
        # Direct string match (case-insensitive)
        if actual.lower() == expected.lower():
            matches.append(f"Column {col_letter} (row {row}): found '{actual}' == '{expected}'")
            return True
        # Check if expected is contained in actual
        if expected.lower() in actual.lower():
            matches.append(f"Column {col_letter} (row {row}): found '{actual}' contains '{expected}'")
            return True
        # Numeric close match
        if numbers_close(actual, expected):
            matches.append(f"Column {col_letter} (row {row}): found '{actual}' ~= '{expected}' (numeric match)")
            return True
        # For percentage: handle '3%' vs '0.03' or '3.0%' etc.
        if '%' in expected:
            exp_num = expected.replace('%', '').strip()
            if cell_val is not None:
                try:
                    fval = float(cell_val)
                    # openpyxl might store 3% as 0.03
                    if abs(fval - float(exp_num) / 100.0) < 0.015:
                        matches.append(f"Column {col_letter} (row {row}): found '{cell_val}' matches '{expected}' as decimal")
                        return True
                    # Or it might store as 3.0 meaning 3%
                    if abs(fval - float(exp_num)) < 1.5:
                        matches.append(f"Column {col_letter} (row {row}): found '{cell_val}' matches '{expected}'")
                        return True
                except (ValueError, TypeError):
                    pass
            # Also check if actual string contains %
            if '%' in actual:
                try:
                    actual_pct = float(actual.replace('%', '').strip())
                    expected_pct = float(exp_num)
                    if abs(actual_pct - expected_pct) < 1.5:
                        matches.append(f"Column {col_letter} (row {row}): found '{actual}' ~= '{expected}' (percentage match)")
                        return True
                except (ValueError, TypeError):
                    pass
        # For dates: try multiple formats
        if '2026' in expected:
            if '2026-04-15' in actual or '04/15/2026' in actual or '4/15/2026' in actual or '15/04/2026' in actual or '20260415' in actual:
                matches.append(f"Column {col_letter} (row {row}): found '{actual}' matches date '{expected}'")
                return True
        # For negative numbers, also try matching with extra whitespace or different minus signs
        if expected.startswith('-'):
            try:
                actual_num = float(actual.replace('\u2212', '-').replace('\u2013', '-'))
                expected_num = float(expected)
                if abs(actual_num - expected_num) <= 1.5:
                    matches.append(f"Column {col_letter} (row {row}): found '{actual}' ~= '{expected}' (close enough)")
                    return True
            except (ValueError, TypeError):
                pass
        # General numeric tolerance: if both are numbers, allow +-2
        try:
            actual_num = float(actual.replace(',', '').replace('\u2212', '-').replace('\u2013', '-').replace('%', ''))
            expected_num = float(expected.replace(',', '').replace('%', ''))
            if abs(actual_num - expected_num) <= 2.0:
                matches.append(f"Column {col_letter} (row {row}): found '{actual}' ~= '{expected}' (within +-2)")
                return True
        except (ValueError, TypeError):
            pass
        errors.append(f"Column {col_letter} (row {row}): expected '{expected}', found '{actual}' (raw: {repr(cell_val)})")
        return False

    # Define expected values per the rubric
    # Rubric says column N = 3%
    checks = [
        ('A', '2026-04-15', 1),
        ('B', '2026-04-15-003', 2),
        ('C', 'Waco Transfer', 3),
        ('D', '26', 4),
        ('E', '26', 5),
        ('F', '520', 6),
        ('G', '516', 7),
        ('H', '-5', 8),
        ('I', '-4', 9),
        ('J', '-4', 10),
        ('K', '-4', 11),
        ('L', 'Tier 3', 12),
        ('M', '-4', 13),
        ('N', '3%', 14),
    ]

    for col_letter, expected, col_idx in checks:
        check_cell(col_letter, expected, col_idx)

    # Check column P (16) or Q (17) for "Received - Pending Put-Away"
    target_text = "Received - Pending Put-Away"
    found_status = False
    # Check columns O through R to be generous
    for col_idx, col_name in [(15, 'O'), (16, 'P'), (17, 'Q'), (18, 'R')]:
        col_val = normalize(ws.cell(row=row, column=col_idx).value)
        if target_text.lower() in col_val.lower():
            matches.append(f"Column {col_name} (row {row}): found '{col_val}' contains '{target_text}'")
            found_status = True
            break
        if 'pending put' in col_val.lower():
            matches.append(f"Column {col_name} (row {row}): found '{col_val}' close match to '{target_text}'")
            found_status = True
            break
        if 'received' in col_val.lower() and 'pending' in col_val.lower():
            matches.append(f"Column {col_name} (row {row}): found '{col_val}' close match to '{target_text}'")
            found_status = True
            break
    if not found_status:
        vals = []
        for col_idx, col_name in [(15, 'O'), (16, 'P'), (17, 'Q'), (18, 'R')]:
            vals.append(f"{col_name}='{normalize(ws.cell(row=row, column=col_idx).value)}'")
        errors.append(f"Columns O-R (row {row}): {', '.join(vals)} — expected '{target_text}' in P or Q")

    total_checks = len(checks) + 1  # +1 for the P/Q status check
    passed_checks = len(matches)
    score = passed_checks / total_checks

    if len(errors) == 0:
        return {"pass": True, "score": 1.0, "feedback": f"All {total_checks} checks passed for row {row}. Details: " + "; ".join(matches)}
    else:
        # Be lenient: pass if 85% or more checks pass
        passed = score >= 0.85
        return {"pass": passed, "score": score, "feedback": f"{passed_checks}/{total_checks} checks passed (row {row}). Errors: " + "; ".join(errors) + ". Matches: " + "; ".join(matches)}
